// Import required libraries
const cron = require('node-cron');
const { sendNotification } = require('./notificationService'); // Assuming you have a notification service
const Tasks = require('./models/Tasks'); // Assuming a Task model for Mongoose

/**
 * Scheduling Engine for Daily Reminder System.
 * This engine handles recurring tasks and sends notifications via Telegram.
 * It uses node-cron to manage the scheduling of tasks.
 */

// Function to schedule notifications based on task data
function scheduleTaskNotifications(task) {
    // Extracting time and recurrence information
    const { recurrence } = task;

    // Define the cron expression based on the recurrence type
    let cronExpression;
    if (recurrence.type === 'daily') {
        cronExpression = `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * *`; // Every day at specified time
    } else if (recurrence.type === 'weekly') {
        const days = recurrence.daysOfWeek.map(day => day.toString()).join(',');
        cronExpression = `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * ${days}`; // specified days
    } else {
        throw new Error('Invalid recurrence type');
    }

    // Scheduling the task
    cron.schedule(cronExpression, async () => {
        try {
            // Fetch the updated task to get the correct assignee
            const updatedTask = await Tasks.findById(task.id);
            const assigneeId = updatedTask.assignees[updatedTask.rotationIndex];

            // Check availability of current assignee
            if (!updatedTask.unavailableMembers.includes(assigneeId)) {
                await sendNotification(updatedTask, assigneeId);

                // Log the success
                console.log(`Notification sent for task: ${task.title} to user: ${assigneeId}`);
            } else {
                // Rotate to next available member
                updatedTask.rotationIndex = (updatedTask.rotationIndex + 1) % updatedTask.assignees.length;
                await updatedTask.save(); // Save updated rotation index
            }
        } catch (error) {
            console.error(`Error scheduling task ${task.id}: `, error);
            // Better error handling can be implemented if needed
        }
    });
}

/**
 * Main function to initiate scheduling for all active tasks
 */
async function initSchedulingEngine() {
    const tasks = await Tasks.find({ status: 'active' }); // Fetch active tasks
    tasks.forEach(scheduleTaskNotifications); // Schedule notifications for each task
}

// Initialize the scheduling engine on module load
initSchedulingEngine();

module.exports = { initSchedulingEngine }; // Export function for testing or other uses
